mapper.select:
select p.*, comm.nx_community_name as community_name
from nx_customer_promoter p
left join nx_community comm on p.community_id = comm.nx_community_id

    and p.community_id = #{communityId}
    and p.commerce_id = #{commerceId}
    and p.promoter_status = #{promoterStatus}

order by p.created_at desc
limit #{offset}, #{limit}

mapper.update:
update nx_customer_promoter
promoter_name = #{promoterName}, promoter_phone = #{promoterPhone}, promoter_type = #{promoterType}, promoter_status = #{promoterStatus}, cooperation_start_at = #{cooperationStartAt}, cooperation_end_at = #{cooperationEndAt}, disabled_at = #{disabledAt}, disabled_reason = #{disabledReason},
where nx_customer_promoter_id = #{nxCustomerPromoterId}
